1981 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1982 |     function applyLocalPatch(content, ops) {
1983 |         let lines = content.split('\n');
1984 |         let logs = [];
1985 |         let success = true;
1986 | 
1987 |         if (typeof ops === 'string') {
1988 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1989 |         }
1990 | 
1991 |         ops.forEach(op => {
1992 |             if (op.action === 'comment') return;
1993 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1994 |             
1995 |             if (op.action === 'replace_block') {
1996 |                 // Strategy 1: Exact String Match (Fastest)
1997 |                 const currentStr = lines.join('\n');
1998 |                 if (currentStr.includes(op.find_block)) {
1999 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2000 |                     logs.push('Exact match applied');
2001 |                     return;
2002 |                 }
2003 | 
2004 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2005 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2006 |                 if (searchLines.length === 0) return;
2007 | 
2008 |                 let matchStart = -1;
2009 |                 let matchEnd = -1;
2010 | 
2011 |                 // Scan file lines
2012 |                 for (let i = 0; i < lines.length; i++) {
2013 |                     // If first line matches (ignoring whitespace)
2014 |                     if (lines[i].trim() === searchLines[0]) {
2015 |                         // Check subsequent lines
2016 |                         let allMatch = true;
2017 |                         let fileOffset = 0;
2018 |                         let searchOffset = 1;
2019 |                         
2020 |                         while (searchOffset < searchLines.length) {
2021 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2022 |                             const nextFile = lines[i + fileOffset + 1].trim();
2023 |                             // Skip empty lines in file if they aren't in search block
2024 |                             if (nextFile === '') {
2025 |                                 fileOffset++;
2026 |                                 continue;
2027 |                             }
2028 |                             if (nextFile !== searchLines[searchOffset]) {
2029 |                                 allMatch = false;
2030 |                                 break;
2031 |                             }
2032 |                             fileOffset++;
2033 |                             searchOffset++;
2034 |                         }
2035 | 
2036 |                         if (allMatch) {
2037 |                             matchStart = i;
2038 |                             matchEnd = i + fileOffset;
2039 |                             break;
2040 |                         }
2041 |                     }
2042 |                 }
2043 | 
2044 |                 if (matchStart !== -1) {
2045 |                     // Replace the range of lines
2046 |                     const replacement = op.replace_with.split('\n');
2047 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2048 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2049 |                 } else {
2050 |                     success = false;
2051 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2052 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2053 |                 }
2054 |             }
2055 |         });
2056 |         return { content: lines.join('\n'), success, logs };
2057 |     }
