4720 |     // --- GENERIC UI ---
4721 |     function formatBytes(bytes) {
4722 |         if (!bytes) return '0 B';
4723 |         const k = 1024;
4724 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4725 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4726 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4727 |     }
