4729 |     function timeAgo(dateString) {
4730 |         const date = new Date(dateString);
4731 |         const now = new Date();
4732 |         const seconds = Math.floor((now - date) / 1000);
4733 |         if (seconds < 10) return 'just now';
4734 |         if (seconds < 60) return seconds + 's ago';
4735 |         const minutes = Math.floor(seconds / 60);
4736 |         if (minutes < 60) return minutes + 'm ago';
4737 |         const hours = Math.floor(minutes / 60);
4738 |         if (hours < 24) return hours + 'h ago';
4739 |         return date.toLocaleDateString();
4740 |     }
