4877 | 
4878 |         const attemptNavigation = async () => {
4879 |             const element = document.querySelector(selector);
4880 |             
4881 |             if (element) {
4882 |                 console.log("[DeepJump] Element found. Scrolling...");
4883 |                 
4884 |                 // Wait for any tab transition animations
4885 |                 await new Promise(r => setTimeout(r, 300));
4886 | 
4887 |                 let offsetTop = 0;
4888 |                 let curr = element;
4889 |                 while (curr && curr !== scrollContainer) {
4890 |                     offsetTop += curr.offsetTop;
4891 |                     curr = curr.offsetParent;
4892 |                 }
4893 | 
4894 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
4895 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
4896 | 
4897 |                 // Visual Highlight
