4904 |                 }, 3000);
4905 |                 
4906 |                 console.groupEnd();
4907 |                 return true;
4908 |             }
4909 | 
4910 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
4911 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
4912 |                 retryCount++;
4913 |                 showGlobalToast("🔍 Searching deeper...");
4914 |                 
4915 |                 await loadMoreFn(); 
4916 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
4917 |                 return attemptNavigation();
